import React from 'react';
import { Link } from 'react-router-dom';

const HeroSection: React.FC = () => {
    return (
        <div className="relative h-[90vh] flex flex-col justify-center items-center text-center px-4">
            {/* Background image */}
            <div 
                className="absolute inset-0 bg-cover bg-center"
                style={{ backgroundImage: 'url(/images/hero-bg.jpg)' }}
            ></div>

            {/* Soft pink overlay */}
            <div className="absolute inset-0 bg-pink-200 bg-opacity-20"></div>

            {/* Content */}
            <div className="relative z-10 text-white drop-shadow-lg">
                <h1 className="text-5xl font-extrabold mb-4">
                    Welcome to <span className="text-pink-400">TravElle</span>
                </h1>
                <p className="text-lg mb-8 text-pink-100">
                    Your travel companion for unforgettable experiences.
                </p>
                <Link 
                    to="/signup" 
                    className="bg-pink-500 hover:bg-pink-600 text-white font-semibold py-3 px-6 rounded-lg shadow-lg transition duration-300"
                >
                    Start Your Journey
                </Link>
            </div>
        </div>
    );
};

export default HeroSection;
